SELECT albums.title
FROM albums
WHERE album_type = 'album';

SELECT title, release_date
FROM albums
ORDER BY release_date;

SELECT subscription_plans.name, subscription_plans.monthly_price
FROM subscription_plans
ORDER BY subscription_plans.monthly_price DESC;

SELECT COUNT(payment_id) AS completed_payments
FROM payments
WHERE payment_status = 'completed';

SELECT COUNT(event_id) AS play_count
FROM play_events
WHERE event_type = 'play';

SELECT COUNT(DISTINCT user_id) AS organic_signups
FROM users
WHERE usr_acq_src = 1;

SELECT COUNT(*) AS total_singles
FROM tracks
WHERE album_id IS NULL;
